package domain

import (
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

// Chunk is the atomic unit of indexed content.
// One per ## section in a markdown document.
type Chunk struct {
	QualifiedID  string    `json:"qualifiedId"`
	SectionID    string    `json:"sectionId"`
	DocumentSlug string    `json:"documentSlug"`
	Title        string    `json:"title"`
	Content      string    `json:"content"`
	Vector       []float32 `json:"-"`
	Scope        string    `json:"scope"`
	Kind         string    `json:"kind"`
	Tags         []string  `json:"tags"`
	Position     int       `json:"position"`
}

// Document represents a source markdown file during indexing.
// Transient: not stored directly, but its metadata propagates to chunks.
type Document struct {
	Path        string
	Slug        string
	Title       string
	ContentHash string
	Scope       string
	Kind        string
	Tags        []string
	FrontMatter FrontMatter
}

// FrontMatter holds metadata extracted from YAML front matter.
type FrontMatter struct {
	Title      string   `yaml:"title"`
	Kind       string   `yaml:"kind"`
	Date       string   `yaml:"date"`
	Tags       []string `yaml:"tags"`
	Status     string   `yaml:"status"`
	Supersedes string   `yaml:"supersedes"`
	Related    []string `yaml:"related"`
	Scope      string   `yaml:"scope"`
	Raw        map[string]any
}

// IndexResult summarises an index operation.
type IndexResult struct {
	Indexed   int
	Unchanged int
	Removed   int
	Errors    int
	Chunks    int
	Duration  time.Duration
	Details   []IndexDetail
	FileErrors []IndexFileError
}

// IndexDetail tracks per-document indexing results.
type IndexDetail struct {
	Path   string `json:"path"`
	Slug   string `json:"slug"`
	Action string `json:"action"`
	Chunks int    `json:"chunks"`
	Scope  string `json:"scope"`
	Kind   string `json:"kind"`
}

// IndexFileError captures a per-file error during directory indexing.
type IndexFileError struct {
	Path    string `json:"path"`
	Message string `json:"message"`
}

// StatusInfo holds server status information.
type StatusInfo struct {
	Ready            bool
	Uptime           time.Duration
	DocumentCount    int
	ChunkCount       int
	GlobalDocuments  int
	GlobalChunks     int
	ProjectDocuments int
	ProjectChunks    int
	EmbedderBackend  string
	EmbedderModel    string
	EmbedderDims     int
	EmbedderStatus   string
}

var slugCleanRe = regexp.MustCompile(`[^a-z0-9-]+`)
var dashCollapseRe = regexp.MustCompile(`-{2,}`)

// SlugFromPath normalises a filename to a URL-safe slug.
// "docs/fpf-spec.md" -> "fpf-spec"
func SlugFromPath(path string) string {
	base := filepath.Base(path)
	ext := filepath.Ext(base)
	name := strings.TrimSuffix(base, ext)
	slug := strings.ToLower(name)
	slug = slugCleanRe.ReplaceAllString(slug, "-")
	slug = dashCollapseRe.ReplaceAllString(slug, "-")
	slug = strings.Trim(slug, "-")
	if slug == "" {
		return "untitled"
	}
	return slug
}

// QualifiedID produces the "{slug}:{sectionID}" format used as the bleve document ID.
func QualifiedID(slug, sectionID string) string {
	return slug + ":" + sectionID
}
